import React, { useEffect, useState, useRef } from 'react';
import toast from 'react-hot-toast';
import { getBooksAPI, createBookAPI, updateBookAPI, deleteBookAPI } from '../../api';

const CATEGORIES = ['Science', 'Technology', 'History', 'Literature', 'Philosophy', 'Biography'];
const CAT_ICONS = { Science:'⚗️', Technology:'💻', History:'📜', Literature:'✍️', Philosophy:'🧠', Biography:'🌍' };

const defaultForm = {
  title:'', author:'', isbn:'', category:'Science',
  totalCopies:1, publisher:'', publishedYear:'',
  description:'', coverImage:'', language:'English', pages:''
};

export default function BooksPage() {
  const [books, setBooks] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [category, setCategory] = useState('All');
  const [showModal, setShowModal] = useState(false);
  const [editing, setEditing] = useState(null);
  const [form, setForm] = useState(defaultForm);
  const [saving, setSaving] = useState(false);
  const [imgPreview, setImgPreview] = useState('');
  const [imgTab, setImgTab] = useState('url');
  const [urlInput, setUrlInput] = useState('');
  const fileInputRef = useRef();

  useEffect(() => { load(); }, [search, category]);

  const load = async () => {
    try {
      setLoading(true);
      const r = await getBooksAPI({ search, category });
      setBooks(r.data.data);
    } catch { toast.error('Failed to load books'); }
    finally { setLoading(false); }
  };

  const openAdd = () => {
    setEditing(null); setForm(defaultForm);
    setImgPreview(''); setUrlInput(''); setImgTab('url');
    setShowModal(true);
  };

  const openEdit = (b) => {
    setEditing(b);
    setForm({
      title:b.title, author:b.author, isbn:b.isbn,
      category:b.category, totalCopies:b.totalCopies,
      publisher:b.publisher||'', publishedYear:b.publishedYear||'',
      description:b.description||'', coverImage:b.coverImage||'',
      language:b.language||'English', pages:b.pages||''
    });
    const isBase64 = b.coverImage?.startsWith('data:');
    setImgPreview(b.coverImage||'');
    setUrlInput(isBase64 ? '' : (b.coverImage||''));
    setImgTab(isBase64 ? 'upload' : 'url');
    setShowModal(true);
  };

  const close = () => {
    setShowModal(false); setEditing(null);
    setForm(defaultForm); setImgPreview(''); setUrlInput('');
  };

  const hc = (e) => setForm(p => ({ ...p, [e.target.name]: e.target.value }));

  // URL tab
  const handleUrlChange = (e) => {
    const url = e.target.value;
    setUrlInput(url);
    setImgPreview(url);
    setForm(p => ({ ...p, coverImage: url }));
  };

  // File upload — compress to max 800px & quality 0.7 before saving
  const processImage = (file) => {
    if (!file) return;
    if (!file.type.startsWith('image/')) { toast.error('Please select an image file'); return; }

    const img = new Image();
    const objectUrl = URL.createObjectURL(file);
    img.onload = () => {
      const canvas = document.createElement('canvas');
      const MAX = 600;
      let w = img.width, h = img.height;
      if (w > h) { if (w > MAX) { h = h * MAX / w; w = MAX; } }
      else { if (h > MAX) { w = w * MAX / h; h = MAX; } }
      canvas.width = w; canvas.height = h;
      const ctx = canvas.getContext('2d');
      ctx.drawImage(img, 0, 0, w, h);
      const compressed = canvas.toDataURL('image/jpeg', 0.7);
      setImgPreview(compressed);
      setForm(p => ({ ...p, coverImage: compressed }));
      URL.revokeObjectURL(objectUrl);
      toast.success('Image ready!');
    };
    img.src = objectUrl;
  };

  const handleFileChange = (e) => processImage(e.target.files[0]);
  const handleDrop = (e) => {
    e.preventDefault();
    processImage(e.dataTransfer.files[0]);
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      setSaving(true);
      const payload = { ...form };
      if (editing) {
        await updateBookAPI(editing._id, payload);
        toast.success('Book updated!');
      } else {
        await createBookAPI(payload);
        toast.success('Book added!');
      }
      close(); load();
    } catch (err) {
      toast.error(err.response?.data?.message || 'Error saving book');
    } finally { setSaving(false); }
  };

  const handleDelete = async (b) => {
    if (!window.confirm(`Delete "${b.title}"?`)) return;
    try { await deleteBookAPI(b._id); toast.success('Deleted!'); load(); }
    catch (err) { toast.error(err.response?.data?.message || 'Cannot delete'); }
  };

  return (
    <div className="page-enter">
      <div className="ap-header">
        <h1 className="ap-title">📚 Books</h1>
        <button className="ap-btn ap-btn--gold" onClick={openAdd}>+ Add Book</button>
      </div>

      <div className="ap-table-box">
        <div className="ap-table-top">
          <input className="ap-search" placeholder="Search title, author, ISBN..." value={search} onChange={e => setSearch(e.target.value)} />
          <select className="ap-search" style={{width:160}} value={category} onChange={e => setCategory(e.target.value)}>
            <option value="All">All Categories</option>
            {CATEGORIES.map(c => <option key={c} value={c}>{CAT_ICONS[c]} {c}</option>)}
          </select>
          <span className="ap-count">{books.length} books</span>
        </div>

        {loading ? <div className="ap-loading"><div className="spinner"/></div>
        : books.length === 0 ? <div className="ap-empty"><div className="ap-empty-icon">📚</div><p>No books found</p></div>
        : (
          <table className="ap-table">
            <thead><tr><th>Cover</th><th>Title & Author</th><th>ISBN</th><th>Category</th><th>Total</th><th>Available</th><th>Actions</th></tr></thead>
            <tbody>
              {books.map(b => (
                <tr key={b._id}>
                  <td>
                    <div style={{width:36,height:48,borderRadius:4,overflow:'hidden',background:'linear-gradient(135deg,#1a1a3a,#2a2a6a)',display:'flex',alignItems:'center',justifyContent:'center',fontSize:18}}>
                      {b.coverImage
                        ? <img src={b.coverImage} alt="" style={{width:'100%',height:'100%',objectFit:'cover'}} onError={e=>{e.target.style.display='none'}}/>
                        : <span>{CAT_ICONS[b.category]||'📖'}</span>}
                    </div>
                  </td>
                  <td><strong>{b.title}</strong><br/><span style={{fontSize:11,color:'var(--text-muted)'}}>by {b.author}</span></td>
                  <td style={{fontFamily:'monospace',fontSize:12}}>{b.isbn}</td>
                  <td><span className="ap-badge ap-badge--blue">{CAT_ICONS[b.category]} {b.category}</span></td>
                  <td>{b.totalCopies}</td>
                  <td><span className={`ap-badge ${b.availableCopies>0?'ap-badge--green':'ap-badge--red'}`}>{b.availableCopies}</span></td>
                  <td>
                    <div className="ap-actions">
                      <button className="ap-btn ap-btn--ghost ap-btn--sm" onClick={()=>openEdit(b)}>✏️ Edit</button>
                      <button className="ap-btn ap-btn--danger ap-btn--sm" onClick={()=>handleDelete(b)}>🗑️</button>
                    </div>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>

      {showModal && (
        <div
          onClick={close}
          style={{
            position:'fixed',top:0,left:0,right:0,bottom:0,
            background:'rgba(0,0,0,0.82)',
            zIndex:9999,
            overflowY:'auto',
            WebkitOverflowScrolling:'touch',
            backdropFilter:'blur(5px)',
            padding:'32px 16px 60px'
          }}
        >
          <div
            onClick={e=>e.stopPropagation()}
            style={{
              background:'var(--bg-card)',
              border:'1px solid var(--border-color)',
              borderRadius:12,
              padding:32,
              width:'100%',
              maxWidth:600,
              margin:'0 auto',
              position:'relative'
            }}
          >
            <button onClick={close} style={{
              position:'absolute',top:14,right:14,
              width:30,height:30,borderRadius:'50%',
              background:'var(--bg-card2)',border:'1px solid var(--border-color2)',
              color:'var(--text-secondary)',fontSize:13,cursor:'pointer',
              display:'flex',alignItems:'center',justifyContent:'center'
            }}>✕</button>
            <h2 className="ap-modal-title">{editing ? 'Edit Book' : 'Add New Book'}</h2>

            <form onSubmit={handleSubmit} className="ap-form">
              <div className="ap-form-grid">

                {/* Cover Image */}
                <div className="ap-form-group ap-form-full">
                  <label className="ap-form-label">📸 Book Cover Image</label>
                  <div style={{display:'flex',gap:14,alignItems:'flex-start'}}>
                    <div style={{flex:1}}>
                      {/* Tabs */}
                      <div style={{display:'flex',gap:6,marginBottom:10}}>
                        {['url','upload'].map(tab => (
                          <button key={tab} type="button" onClick={()=>setImgTab(tab)} style={{
                            padding:'5px 14px', borderRadius:6, border:'none', cursor:'pointer',
                            fontSize:12, fontWeight:600,
                            background: imgTab===tab ? 'var(--gold)' : 'var(--bg-card2)',
                            color: imgTab===tab ? '#000' : 'var(--text-secondary)'
                          }}>
                            {tab==='url' ? '🔗 URL' : '📁 Upload'}
                          </button>
                        ))}
                      </div>

                      {imgTab === 'url' ? (
                        <input
                          className="ap-form-input"
                          value={urlInput}
                          onChange={handleUrlChange}
                          placeholder="https://example.com/cover.jpg"
                        />
                      ) : (
                        <div
                          onDrop={handleDrop}
                          onDragOver={e=>e.preventDefault()}
                          onClick={()=>fileInputRef.current.click()}
                          style={{
                            border:'2px dashed var(--border-color)', borderRadius:8,
                            padding:'20px 12px', textAlign:'center', cursor:'pointer',
                            background:'var(--bg-card2)'
                          }}
                        >
                          <div style={{fontSize:24,marginBottom:6}}>📁</div>
                          <div style={{fontSize:12,color:'var(--text-secondary)'}}>Click or Drag & Drop</div>
                          <div style={{fontSize:11,color:'var(--text-muted)',marginTop:3}}>JPG/PNG — auto compressed</div>
                          <input ref={fileInputRef} type="file" accept="image/*" style={{display:'none'}} onChange={handleFileChange}/>
                        </div>
                      )}
                    </div>

                    {/* Preview */}
                    <div style={{textAlign:'center',flexShrink:0}}>
                      <div style={{
                        width:60,height:80,borderRadius:6,overflow:'hidden',
                        background:'linear-gradient(135deg,#1a1a3a,#2a2a6a)',
                        display:'flex',alignItems:'center',justifyContent:'center',
                        border:'1px solid var(--border-color2)',fontSize:26,
                        boxShadow:'3px 3px 12px rgba(0,0,0,0.3)'
                      }}>
                        {imgPreview
                          ? <img src={imgPreview} alt="" style={{width:'100%',height:'100%',objectFit:'cover'}} onError={()=>setImgPreview('')}/>
                          : <span>{CAT_ICONS[form.category]||'📖'}</span>
                        }
                      </div>
                      <div style={{fontSize:10,color:'var(--text-muted)',marginTop:4}}>Preview</div>
                    </div>
                  </div>
                </div>

                <div className="ap-form-group ap-form-full">
                  <label className="ap-form-label">Title *</label>
                  <input className="ap-form-input" name="title" value={form.title} onChange={hc} required placeholder="Book title"/>
                </div>
                <div className="ap-form-group">
                  <label className="ap-form-label">Author *</label>
                  <input className="ap-form-input" name="author" value={form.author} onChange={hc} required placeholder="Author name"/>
                </div>
                <div className="ap-form-group">
                  <label className="ap-form-label">ISBN *</label>
                  <input className="ap-form-input" name="isbn" value={form.isbn} onChange={hc} required placeholder="978-..."/>
                </div>
                <div className="ap-form-group">
                  <label className="ap-form-label">Category *</label>
                  <select className="ap-form-input" name="category" value={form.category} onChange={hc}>
                    {CATEGORIES.map(c => <option key={c} value={c}>{CAT_ICONS[c]} {c}</option>)}
                  </select>
                </div>
                <div className="ap-form-group">
                  <label className="ap-form-label">Total Copies *</label>
                  <input className="ap-form-input" type="number" name="totalCopies" value={form.totalCopies} onChange={hc} required min="1"/>
                </div>
                <div className="ap-form-group">
                  <label className="ap-form-label">Publisher</label>
                  <input className="ap-form-input" name="publisher" value={form.publisher} onChange={hc} placeholder="Publisher"/>
                </div>
                <div className="ap-form-group">
                  <label className="ap-form-label">Published Year</label>
                  <input className="ap-form-input" type="number" name="publishedYear" value={form.publishedYear} onChange={hc} placeholder="2023"/>
                </div>
                <div className="ap-form-group">
                  <label className="ap-form-label">Language</label>
                  <select className="ap-form-input" name="language" value={form.language} onChange={hc}>
                    <option>English</option><option>Hindi</option><option>Gujarati</option>
                    <option>Marathi</option><option>Sanskrit</option><option>Other</option>
                  </select>
                </div>
                <div className="ap-form-group">
                  <label className="ap-form-label">Pages</label>
                  <input className="ap-form-input" type="number" name="pages" value={form.pages} onChange={hc} placeholder="350"/>
                </div>
                <div className="ap-form-group ap-form-full">
                  <label className="ap-form-label">Description</label>
                  <textarea className="ap-form-input" name="description" value={form.description} onChange={hc} rows="3" placeholder="Brief description..." style={{resize:'vertical'}}/>
                </div>
              </div>

              <div className="ap-form-actions">
                <button type="button" className="ap-btn ap-btn--ghost" onClick={close}>Cancel</button>
                <button type="submit" className="ap-btn ap-btn--gold" disabled={saving}>
                  {saving ? 'Saving...' : editing ? 'Update Book' : 'Add Book'}
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}
